	('63b62c79-bd18-429a-abf5-27f606e8ab34', '2026-02-07 02:05:28.983897+00', '2026-02-07 02:05:28.983897+00', 'import_missing', 'TS2304', 'Cannot find name - missing component import.', 'src/components/admin/AssetGenerator.tsx', NULL, 'Used new components in JSX without adding them to imports', 'development', 'Add the missing component to the import statement.', 'Before using new components, always add them to imports first.', 1, '2026-02-07 02:05:28.983897+00', true, '{lucide,icons,import}'),
