	('975a2b55-6934-4de2-8f91-3545b1ed2dcd', '2026-02-07 02:05:28.983897+00', '2026-02-07 02:05:28.983897+00', 'type_mismatch', 'TS2741', 'Property is missing in type but required in interface.', 'src/constants/furnitureCatalog.ts', NULL, 'Added new catalog items without the required property', 'development', 'Make the property optional in the interface with ?', 'Check type definitions before adding new data.', 1, '2026-02-07 02:05:28.983897+00', true, '{typescript,interface,type}'),
