INSERT INTO "public"."interactive_quiz_questions" ("id", "session_id", "question_text", "options", "correct_answer", "order_index", "created_at") VALUES
	('6360dd55-b147-4ecf-b5d1-a5918e6934e1', 'bc052c63-ea5a-463d-8b6a-0120d14e0330', '7. 假若保險人不把投保人正感到胃痛一事列作重要事實，其原因必定是： （參考章節：1.2.2）', '{"A": "A. 胃痛是可以透過身體檢查發覺的", "B": "B. 這與投保人的健康狀況沒有關係", "C": "C. 收取附加保費就可以接受這項投保", "D": "D. 這事實不會影響投保人決定是否接受投保或釐定保費"}', 'D', 0, '2026-02-21 13:44:45.211355+00'),
	('12fc6b51-cccb-4396-b391-a7d9fdd46891', 'bc052c63-ea5a-463d-8b6a-0120d14e0330', '9. 任何人對於下列哪些/種人有無限的可保權益？（參考章節：1.2.1）', '{"A": "A. 自己", "B": "B. 自己的兄弟", "C": "C. 自己的雙親", "D": "D. 以上各項"}', 'A', 1, '2026-02-21 13:44:45.211355+00'),
	('ad3c9fc1-6711-4e92-b659-dc038e146dfc', 'bc052c63-ea5a-463d-8b6a-0120d14e0330', '3. 初期的壽險合約：（參考章節：1.1）', '{"A": "A. 本質是永久性的，直到受保人死亡", "B": "B. 與物業按揭有關", "C": "C. 是儲蓄產品", "D": "D. 本質是暫時性的，只為受保人早逝"}', 'D', 2, '2026-02-21 13:44:45.211355+00'),
	('99c5a76f-fb11-4cfb-8e5e-2f844b8234f1', 'bc052c63-ea5a-463d-8b6a-0120d14e0330', '10. 以下哪一項就人壽保險的可保權益的陳述是不正確的？（參考章節：1.2.1）', '{"A": "A. 配偶對另一方擁有可保權益", "B": "B. 父母對其子女均擁有可保權益", "C": "C. 血緣關係一定不會構成可保權益", "D": "D. 監護人對其未成年的受監護人擁有可保權益"}', 'C', 3, '2026-02-21 13:44:45.211355+00'),
	('0e67590f-ce08-44f3-a6ad-bca39d1f3344', 'bc052c63-ea5a-463d-8b6a-0120d14e0330', '4. 在考慮壽險需求的時候，以下哪項並不屬於商業需求，而是個人需求？（參考章節：1.1.1）', '{"A": "A. 關鍵人物", "B": "B. 合伙人", "C": "C. 退休收入", "D": "D. 僱員福利"}', 'C', 4, '2026-02-21 13:44:45.211355+00'),
	('17642334-1eda-4feb-9332-1e2bbfc53a31', 'bc052c63-ea5a-463d-8b6a-0120d14e0330', '2. 人壽保險最初的目的是為早逝的情況支付利益，然而亦可提供以下哪些功能？（參考章節：1.1）', '{"A": "A. 投資", "B": "B. 退休", "C": "C. 儲蓄", "D": "D. 以上所有各項"}', 'D', 5, '2026-02-21 13:44:45.211355+00'),
	('86dc606a-37bd-40ed-b626-18b41a8bc599', 'bc052c63-ea5a-463d-8b6a-0120d14e0330', '1. 人壽保險最初的目的為：（參考章節：1.1）', '{"A": "A. 為退休後支付每個月的生活費", "B": "B. 向被保險人的家屬提供幫助", "C": "C. 為一名海上死亡的船員提供保障", "D": "D. 應付短期債務之用"}', 'B', 6, '2026-02-21 13:44:45.211355+00'),
	('23d0f290-62cf-4b64-a1dc-e6ce3d044e14', 'bc052c63-ea5a-463d-8b6a-0120d14e0330', '8. 個人(自己)對以下哪些人擁有可保權益：
(i) 十歲的兒子
(ii) 配偶
(iii) 一個借錢給自己的人
(iv) 一個向自己借錢的人
